import React, { useState, useEffect } from 'react';
import './CommandeForm.css';

const CommandeForm = ({ selectedCommande, onSuccess, onCancel }) => {
  const [formData, setFormData] = useState({
    idCOM: '',
    codeCli: '',
    codeArt: '',
    dateCom: '',
    QteCom: ''
  });

  const [factureVisible, setFactureVisible] = useState(false);
  const [factureData, setFactureData] = useState(null);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    if (selectedCommande) {
      setFormData({
        ...selectedCommande,
        dateCom: selectedCommande.dateCom ? selectedCommande.dateCom.split('T')[0] : ''
      });
      setFactureVisible(false);
    } else {
      resetForm();
    }
  }, [selectedCommande]);

  const validateForm = ({ codeCli, codeArt, QteCom, dateCom }) => {
    const onlyDigits = /^[0-9]+$/;
    if (!onlyDigits.test(codeCli)) return 'Le code client doit contenir uniquement des chiffres.';
    if (!onlyDigits.test(codeArt)) return 'Le code article doit contenir uniquement des chiffres.';
    if (!onlyDigits.test(QteCom)) return 'La quantité doit contenir uniquement des chiffres.';
    if (!dateCom) return 'La date de commande est requise.';
    return null;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const resetForm = () => {
    setFormData({
      idCOM: '',
      codeCli: '',
      codeArt: '',
      dateCom: '',
      QteCom: ''
    });
    setFactureVisible(false);
    setFactureData(null);
    setMessage('');
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    setError('');
    setMessage('');

    const validationError = validateForm(formData);
    if (validationError) {
      setError(validationError);
      return;
    }

    const method = selectedCommande ? 'PUT' : 'POST';
    const url = selectedCommande
      ? `http://localhost:3001/commandes/${formData.idCOM}`
      : 'http://localhost:3001/commandes';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      setMessage(selectedCommande ? 'Commande modifiée avec succès.' : 'Commande ajoutée avec succès.');
      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      setError(err.message);
    }
  };

  const handleDelete = async () => {
    const confirmDelete = window.confirm('Supprimer cette commande ?');
    if (!confirmDelete) return;

    try {
      const res = await fetch(`http://localhost:3001/commandes/${formData.idCOM}`, {
        method: 'DELETE'
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      setMessage('Commande supprimée avec succès.');
      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      setError(err.message);
    }
  };

  const handleVoirFacture = async () => {
    try {
      const res = await fetch(`http://localhost:3001/commandes/${formData.idCOM}`);
      if (!res.ok) throw new Error('Erreur récupération facture');
      const data = await res.json();

      const cleanedData = {
        ...data,
        dateCom: data.dateCom ? data.dateCom.split('T')[0] : data.dateCom
      };

      setFactureData(cleanedData);
      setFactureVisible(true);
    } catch (error) {
      setError(error.message);
    }
  };

  const handlePrintFacture = () => {
    if (!factureData) return;

    const content = `
      <html>
        <head>
          <title>Facture Commande #${factureData.idCOM}</title>
          <style>
            body { font-family: Arial, sans-serif; padding: 20px; }
            .facture-box {
              border: 1px solid #ccc;
              padding: 15px;
              max-width: 400px;
              margin: auto;
            }
            h3 {
              text-align: center;
            }
            p {
              font-size: 16px;
              margin: 5px 0;
            }
          </style>
        </head>
        <body>
          <div class="facture-box">
            <h3>🧾 Facture Commande #${factureData.idCOM}</h3>
            <p><strong>Client :</strong> ${factureData.nomCli} ${factureData.prenomCli}</p>
            <p><strong>Article :</strong> ${factureData.nomArt}</p>
            <p><strong>Prix unitaire :</strong> ${factureData.prix} €</p>
            <p><strong>Quantité :</strong> ${factureData.QteCom}</p>
            <p><strong>Date :</strong> ${factureData.dateCom}</p>
            <p><strong>Total :</strong> ${(factureData.QteCom * factureData.prix).toFixed(2)} €</p>
          </div>
          <p>Merci pour votre commande</p>
        </body>
      </html>
    `;

    const printWindow = window.open('', '', 'width=600,height=600');
    printWindow.document.write(content);
    printWindow.document.close();
    printWindow.focus();
    printWindow.onload = () => {
      printWindow.print();
      printWindow.close();
    };
  };

  return (
    <div>
      <form onSubmit={handleSubmit} className="commande-form">
        <input
          name="idCOM"
          placeholder="ID Commande"
          value={formData.idCOM}
          onChange={handleChange}
          disabled={!!selectedCommande}
        />
        <input
          name="codeCli"
          placeholder="Code Client"
          value={formData.codeCli}
          onChange={handleChange}
          required
        />
        <input
          name="codeArt"
          placeholder="Code Article"
          value={formData.codeArt}
          onChange={handleChange}
          required
        />
        <input
          type="date"
          name="dateCom"
          placeholder="Date de commande"
          value={formData.dateCom}
          onChange={handleChange}
          required
        />
        <input
          type="number"
          name="QteCom"
          placeholder="Quantité"
          value={formData.QteCom}
          onChange={handleChange}
          required
        />

        <button type="submit">
          {selectedCommande ? 'Modifier' : 'Ajouter'}
        </button>

        <div className="button-group">
          {selectedCommande && (
            <>
              <button type="button" onClick={handleDelete}>Supprimer</button>
              <button type="button" onClick={onCancel}>Annuler</button>
            </>
          )}
          <button type="button" onClick={handleVoirFacture}>Voir facture</button>
        </div>

        {message && <div className="success">{message}</div>}
        {error && <div className="error">{error}</div>}
      </form>

      {factureVisible && factureData && (
        <div className="parent">
          <div className="facture-box">
            <h3>🧾 Facture Commande #{factureData.idCOM}</h3>
            <p><strong>Client :</strong> {factureData.nomCli} {factureData.prenomCli}</p>
            <p><strong>Article :</strong> {factureData.nomArt}</p>
            <p><strong>Prix unitaire :</strong> {factureData.prix} €</p>
            <p><strong>Quantité :</strong> {factureData.QteCom}</p>
            <p><strong>Date :</strong> {factureData.dateCom}</p>
            <p><strong>Total :</strong> {(factureData.QteCom * factureData.prix).toFixed(2)} €</p>

            <button onClick={handlePrintFacture}>🖨️ Imprimer la facture</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default CommandeForm;
